def merge_two_lists(list1: List[int], list2: List[int]) -> List[int]:
    l1 = build_list(list1)
    l2 = build_list(list2)

    def merge(a, b):
        if not a:
            return b
        if not b:
            return a
        if a.val <= b.val:
            a.next = merge(a.next, b)
            return a
        else:
            b.next = merge(a, b.next)
            return b

    return list_to_arr(merge(l1, l2))

